typedef struct APPX_PACKAGE_SETTINGS {
  BOOL forceZip32;
  IUri *hashMethod;
} APPX_PACKAGE_SETTINGS;

HRESULT GetXmlDom(
[out] IXMLDOMDocument **dom);
HRESULT GetCompressedSize(   [out, retval] UINT32 *size);
HRESULT GetHash(
[out]         UINT32 *bufferSize,
[out, retval] BYTE   **buffer);
HRESULT GetCurrent(
[out, retval] IAppxBlockMapBlock **block);
HRESULT GetHasCurrent(
[out, retval] BOOL *hasCurrent);
HRESULT MoveNext(
[out, retval] BOOL *hasNext);
HRESULT GetBlocks(
[out, retval] IAppxBlockMapBlocksEnumerator **blocks);
HRESULT GetLocalFileHeaderSize(   [out, retval] UINT32 *lfhSize);
HRESULT GetName(
[out, retval] LPWSTR *name);
HRESULT GetUncompressedSize(   [out, retval] UINT64 *size);
HRESULT ValidateFileHash(
[in]          IStream *fileStream,
[out, retval] BOOL    *isValid);
HRESULT GetCurrent(
[out, retval] IAppxBlockMapFile **file);
HRESULT GetHasCurrent(
[out, retval] BOOL *hasCurrent);
HRESULT MoveNext(
[out, retval] BOOL *hasCurrent);
HRESULT GetFile(
[in]          LPCWSTR           filename,
[out, retval] IAppxBlockMapFile **file);
HRESULT GetFiles(
[out, retval] IAppxBlockMapFilesEnumerator **enumerator);
HRESULT GetHashMethod(
[out, retval] IUri **hashMethod);
HRESULT GetStream(
[out, retval] IStream **blockMapStream);
HRESULT CreateBundleManifestReader(
[in]          IStream                   *inputStream,
[out, retval] IAppxBundleManifestReader **manifestReader);

typedef struct PACKAGE_ID {
  PACKAGE_VERSION version;
  PWSTR name;
  PWSTR publisher;
  PWSTR resourceId;
  PWSTR architecture;
} PACKAGE_ID;

typedef enum APPX_ENCRYPTED_PACKAGE_OPTIONS {
    APPX_ENCRYPTED_PACKAGE_OPTION_NONE,
    APPX_ENCRYPTED_PACKAGE_OPTION_DIFFUSION,
    APPX_ENCRYPTED_PACKAGE_OPTION_PAGE_HASHING
} APPX_ENCRYPTED_PACKAGE_OPTIONS;
